def extended_gcd(a, b):
    """
    Compute the greatest common divisor (GCD) of two integers `a` and `b`, along with the coefficients (x, y) that satisfy the equation `a * x + b * y = gcd(a, b)`.
    """
    if b == 0:
        return (a, 1, 0)
    else:
        g, x, y = extended_gcd(b, a % b)
        return (g, y, x - (a // b) * y)
